// 全台 16 個熱門騎乘代表點，覆蓋北/中/南/東四區
// 0.1° 格網（~11km）會吃下附近活動的 webhook 查詢
const locations = [
  // 北部
  { region: 'north',   name: '陽明山擎天崗', lat: 25.16, lon: 121.57 },
  { region: 'north',   name: '北宜坪林',     lat: 24.94, lon: 121.71 },
  { region: 'north',   name: '北橫巴陵',     lat: 24.69, lon: 121.39 },
  { region: 'north',   name: '風櫃嘴',       lat: 25.13, lon: 121.62 },
  // 中部
  { region: 'central', name: '武嶺',         lat: 24.14, lon: 121.30 },
  { region: 'central', name: '日月潭',       lat: 23.85, lon: 120.92 },
  { region: 'central', name: '八卦山',       lat: 24.07, lon: 120.54 },
  { region: 'central', name: '大甲海線',     lat: 24.35, lon: 120.62 },
  // 南部
  { region: 'south',   name: '阿里山',       lat: 23.51, lon: 120.80 },
  { region: 'south',   name: '壽卡',         lat: 22.21, lon: 120.85 },
  { region: 'south',   name: '高雄美濃',     lat: 22.90, lon: 120.54 },
  { region: 'south',   name: '台南關仔嶺',   lat: 23.34, lon: 120.51 },
  // 東部
  { region: 'east',    name: '太魯閣',       lat: 24.16, lon: 121.62 },
  { region: 'east',    name: '蘇花清水',     lat: 24.20, lon: 121.69 },
  { region: 'east',    name: '花東玉里',     lat: 23.34, lon: 121.31 },
  { region: 'east',    name: '台東鹿野',     lat: 22.91, lon: 121.13 },
];

return locations.map(loc => ({ json: loc }));

// 直接在 Code 節點組好完整 SQL（多行 VALUES inline）
// 避開 n8n queryReplacement 用逗號切參數的問題
const items = $input.all();
const out = [];

const esc = (s) => String(s).replace(/'/g, "''");
const num = (v) => (v === null || v === undefined || Number.isNaN(v)) ? 'NULL' : v;
const txt = (v) => (v === null || v === undefined) ? 'NULL' : `'${esc(v)}'`;

for (let i = 0; i < items.length; i++) {
  const fc = items[i].json.list || [];
  const loc = $('Locations').itemMatching(i).json;
  if (fc.length === 0) continue;

  const lat_round = Math.round(loc.lat * 10) / 10;
  const lon_round = Math.round(loc.lon * 10) / 10;

  const rows = fc.map(f => {
    const ft = new Date(f.dt * 1000).toISOString();
    return `(${lat_round}, ${lon_round}, '${ft}'::timestamptz, `
      + `${num(f.main?.temp)}, ${num(f.main?.feels_like)}, ${num(f.main?.humidity)}, `
      + `${num(f.pop ?? 0)}, ${num(f.rain?.['3h'] ?? 0)}, `
      + `${num(f.wind?.speed)}, ${num(f.wind?.deg)}, `
      + `${txt(f.weather?.[0]?.main)}, ${txt(f.weather?.[0]?.description)}, ${txt(f.weather?.[0]?.icon)}, `
      + `now())`;
  });

  const sql = `INSERT INTO weather_points (
  lat_round, lon_round, forecast_time,
  temp, feels_like, humidity,
  pop, rain_3h, wind_speed, wind_deg,
  weather_main, weather_desc, icon, fetched_at
) VALUES
${rows.join(',\n')}
ON CONFLICT (lat_round, lon_round, forecast_time) DO UPDATE SET
  temp = EXCLUDED.temp,
  feels_like = EXCLUDED.feels_like,
  humidity = EXCLUDED.humidity,
  pop = EXCLUDED.pop,
  rain_3h = EXCLUDED.rain_3h,
  wind_speed = EXCLUDED.wind_speed,
  wind_deg = EXCLUDED.wind_deg,
  weather_main = EXCLUDED.weather_main,
  weather_desc = EXCLUDED.weather_desc,
  icon = EXCLUDED.icon,
  fetched_at = now();`;

  out.push({ json: {
    region: loc.region, name: loc.name,
    lat_round, lon_round,
    slot_count: rows.length,
    sql,
  }});
}

return out;
